#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        int w;
        bool impossible = false;
        int trips = 0;
        int cur = 0;
        for(int i=0;i<N;i++){
            scanf("%d", &w);
            if(w > K) impossible = true;
            if(impossible) continue; // still read remaining input
            if(cur + w > K){
                trips++;
                cur = w;
            }else{
                cur += w;
            }
        }
        if(impossible){
            printf("-1\n");
        }else{
            if(cur>0) trips++; // last unfinished trip
            printf("%d\n", trips);
        }
    }
    return 0;
}

