#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        impossible = False
        trips = 0
        cur = 0
        for _ in range(N):
            w = int(next(it))
            if w > K:
                impossible = True
            if impossible:
                continue
            if cur + w > K:
                trips += 1
                cur = w
            else:
                cur += w
        if impossible:
            out_lines.append('-1')
        else:
            if cur > 0:
                trips += 1
            out_lines.append(str(trips))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

